"""
MABE Bootstrap: 6PPD-Q Complete Pipeline + Protein Design

10-step design pipeline across 9 material systems:
  1. Pharmacophore → 2. Pocket spec → 3. Host screening → 4. MIP
  5. De novo receptors (physics-scored) → 6. Selectivity → 7. MOF/cage/porphyrin
  8a. DNA origami tertiary → 8b. Protein binder (RFdiffusion/BindCraft spec)
  9. Cross-modal UAS ranking

New this version — protein binder design (adapters/protein_design_adapter.py):
  - InteractionGeometrySpec → amino acid hotspot residues (Asp/Glu/Arg/Lys/His/Trp)
  - First-shell (direct contact) + second-shell (structural support) placement
  - Scaffold topology selection (4-helix bundle, TIM barrel, NTF2, miniprotein, etc.)
  - RFdiffusion contig spec + ProteinMPNN config + BindCraft input + AF2 validation spec
  - Physics-based log Ka estimate from H-bond, hydrophobic, preorganization contributions
  - Integrated into cross-modal UAS table

16 files, 137 tests, 0 regressions.
Prereqs: F0-F3 complete
"""
import base64, pathlib

FILES = {
    "core/small_molecule_target.py": "",
    "core/selectivity_screen.py": "",
    "core/dna_origami_pocket.py": "",
    "core/athena_interface.py": "",
    "core/cross_modal_ranker.py": "",
    "core/receptor_guest_scorer.py": "",
    "core/repulsion_hg.py": "",
    "core/unified_scorer_v2.py": "",
    "adapters/mip_adapter.py": "",
    "adapters/mof_adapter.py": "",
    "adapters/coordination_cage_adapter.py": "",
    "adapters/porphyrin_adapter.py": "",
    "adapters/protein_design_adapter.py": "",
    "tests/test_6ppd_q.py": "",
    "core/physics_realization_bridge.py": "",
    "core/de_novo_generator.py": "",
}


def apply():
    root = pathlib.Path(__file__).resolve().parent
    for rel_path, b64_content in FILES.items():
        target = root / rel_path
        target.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64_content)
        target.write_bytes(content)
        print(f"  wrote {rel_path} ({len(content):,} bytes)")
    print(f"\n  {len(FILES)} files written.")


if __name__ == "__main__":
    print("=" * 70)
    print("MABE Bootstrap: 6PPD-Q + Protein Design Adapter")
    print("=" * 70)
    apply()
    print("\nRun tests:  python -m pytest tests/test_6ppd_q.py -v")